/**
 * Desktop navigation — rendered as a centered pill inside the header.
 *
 * LAYOUT ORDER (explicit, not API-driven):
 *   [Home] [About] [Services ▼] [Resources ▼] [Career] [Contact] [● Track Consultation]
 *
 * MEGA MENU DROPDOWN:
 * ────────────────────
 * The Services and Resources dropdowns use a premium opaque mega menu
 * design with CSS-only "Hover Bridge" interaction:
 *
 *   1. The parent wrapper has `group` class
 *   2. The dropdown is absolutely positioned below the trigger
 *   3. A `pt-3` (12px) invisible bridge keeps the mouse within the
 *      group hover bounding box while traveling to the card
 *   4. The dropdown animates via CSS:
 *      - Default: invisible opacity-0 scale-95
 *      - On hover: group-hover:visible group-hover:opacity-100 group-hover:scale-100
 *      - On keyboard focus: group-focus-within:visible etc.
 *      - transition-all duration-200 origin-top
 *
 * This approach is 60fps because it uses CSS transforms and opacity,
 * not React state changes that trigger re-renders.
 *
 * THEME ADAPTATION:
 *   Light mode → White/cream card, dark text
 *   Dark mode → Opaque #25201d card, white text
 *
 * BACKEND / ADMIN INTEGRATION NOTES:
 * ──────────────────────────────────
 * Nav structure is defined in staticNavigation.ts. To change the items,
 * order, or labels, edit that file — NOT this component.
 *
 * If API-driven navigation is re-enabled in the future, replace the
 * leftLinks/rightLinks/highlightLink props with a single navigationItems
 * prop and parse using utils/navigation.ts utilities.
 */

import type { FocusEvent } from "react";
import { ChevronDown } from "lucide-react";
import { MegaMenuColumns } from "@/exxonim/components/navigation/MegaMenuColumns";
import type { FeatureBox, MegaMenuLayout, MenuColumn, MenuKey, MenuItem } from "@/exxonim/components/navigation/types";
import { routes } from "@/exxonim/routes";
import { cn } from "@/exxonim/utils/cn";

interface DesktopNavigationProps {
  brandName: string;
  leftLinks: MenuItem[];
  rightLinks: MenuItem[];
  highlightLink: MenuItem;
  desktopMenu: MenuKey | null;
  resourcesActive: boolean;
  resourcesColumns: MenuColumn[];
  resourcesLayout: MegaMenuLayout;
  resourcesFeatureBox?: FeatureBox;
  resourcesMenuId: string;
  servicesActive: boolean;
  servicesColumns: MenuColumn[];
  servicesLayout: MegaMenuLayout;
  servicesFeatureBox?: FeatureBox;
  servicesMenuId: string;
  closeAllMenus: () => void;
  isActive: (href: string) => boolean;
  onDropdownBlur: (event: FocusEvent<HTMLDivElement>) => void;
  setDesktopMenu: (menu: MenuKey | null) => void;
}

const navLinkBase =
  "relative inline-flex items-center justify-center h-10 px-4 text-[0.825rem] font-medium tracking-wide text-text rounded-full transition-all hover:bg-accent-soft";
const navLinkActive = "bg-accent-soft text-accent";

export function DesktopNavigation({
  brandName,
  leftLinks,
  rightLinks,
  highlightLink,
  desktopMenu,
  resourcesActive,
  resourcesColumns,
  resourcesLayout,
  resourcesFeatureBox,
  resourcesMenuId,
  servicesActive,
  servicesColumns,
  servicesLayout,
  servicesFeatureBox,
  servicesMenuId,
  closeAllMenus,
  isActive,
  onDropdownBlur,
  setDesktopMenu,
}: DesktopNavigationProps) {
  return (
    <div className="hidden xl:flex items-center">
      <nav
        className="inline-flex items-center gap-1 p-1.5 rounded-full bg-surface-soft border border-border-soft"
        aria-label="Primary navigation"
      >
        {/* Left links (Home, About) */}
        {leftLinks.map((link) => (
          <a
            key={link.href}
            href={link.href}
            aria-current={isActive(link.href) ? "page" : undefined}
            onClick={closeAllMenus}
            className={cn(navLinkBase, isActive(link.href) && navLinkActive)}
          >
            {link.label}
          </a>
        ))}

        {/* ═══════════════════════════════════════════════════════
         * SERVICES MEGA MENU — CSS Hover Bridge
         * ═══════════════════════════════════════════════════════
         * The `group` class on the wrapper enables CSS-only hover
         * detection. The dropdown animates via group-hover: classes.
         * `pt-3` creates the invisible hover bridge.
         * React state (`desktopMenu`) is kept for ARIA attributes
         * and Escape key / route-change close behavior only.
         */}
        <div
          className="relative group"
          onMouseEnter={() => setDesktopMenu("services")}
          onMouseLeave={() => setDesktopMenu(null)}
          onFocusCapture={() => setDesktopMenu("services")}
          onBlur={onDropdownBlur}
        >
          <a
            href={routes.services}
            aria-expanded={desktopMenu === "services"}
            aria-controls={servicesMenuId}
            aria-current={servicesActive ? "page" : undefined}
            onClick={closeAllMenus}
            className={cn(navLinkBase, servicesActive && navLinkActive)}
          >
            Services
            <ChevronDown
              className="ml-1 w-4 h-4 transition-transform duration-200
                         group-hover:rotate-180 group-focus-within:rotate-180"
              aria-hidden="true"
            />
          </a>

          {/* Dropdown wrapper — pt-3 is the hover bridge */}
          <div
            id={servicesMenuId}
            aria-hidden={desktopMenu !== "services"}
            className="absolute top-full left-1/2 -translate-x-1/2 pt-3
                       invisible opacity-0 scale-95 origin-top
                       group-hover:visible group-hover:opacity-100 group-hover:scale-100
                       group-focus-within:visible group-focus-within:opacity-100 group-focus-within:scale-100
                       transition-all duration-200 z-50"
          >
            {/* Mega menu card — theme-adaptive */}
            <div className="w-[720px] rounded-[28px] border p-6
                            bg-white border-gray-200 shadow-[0_24px_48px_-12px_rgba(0,0,0,0.12)]
                            dark:bg-[#25201d] dark:border-[#362f2a] dark:shadow-[0_24px_48px_-12px_rgba(0,0,0,0.4)]">
              <MegaMenuColumns
                columns={servicesColumns}
                layout={servicesLayout}
                featureBox={servicesFeatureBox}
                onNavigate={closeAllMenus}
              />

              {/* Footer CTA row */}
              <div className="flex items-center gap-3 mt-5 pt-4 border-t border-gray-100 dark:border-white/5">
                <a
                  href={routes.services}
                  onClick={closeAllMenus}
                  className="inline-flex items-center justify-center h-9 px-5 rounded-full bg-accent text-accent-contrast text-sm font-bold hover:bg-accent-hover transition-all"
                >
                  See All Services
                </a>
                <a
                  href={routes.contact}
                  onClick={closeAllMenus}
                  className="text-sm font-medium text-gray-500 dark:text-[#a39a92] hover:text-accent dark:hover:text-accent transition-colors"
                >
                  Contact {brandName}
                </a>
              </div>
            </div>
          </div>
        </div>

        {/* ═══════════════════════════════════════════════════════
         * RESOURCES MEGA MENU — CSS Hover Bridge
         * ═══════════════════════════════════════════════════════ */}
        <div
          className="relative group"
          onMouseEnter={() => setDesktopMenu("resources")}
          onMouseLeave={() => setDesktopMenu(null)}
          onFocusCapture={() => setDesktopMenu("resources")}
          onBlur={onDropdownBlur}
        >
          <a
            href={routes.resources}
            aria-expanded={desktopMenu === "resources"}
            aria-controls={resourcesMenuId}
            aria-current={resourcesActive ? "page" : undefined}
            onClick={closeAllMenus}
            className={cn(navLinkBase, resourcesActive && navLinkActive)}
          >
            Resources
            <ChevronDown
              className="ml-1 w-4 h-4 transition-transform duration-200
                         group-hover:rotate-180 group-focus-within:rotate-180"
              aria-hidden="true"
            />
          </a>

          {/* Dropdown wrapper — pt-3 is the hover bridge */}
          <div
            id={resourcesMenuId}
            aria-hidden={desktopMenu !== "resources"}
            className="absolute top-full left-1/2 -translate-x-1/2 pt-3
                       invisible opacity-0 scale-95 origin-top
                       group-hover:visible group-hover:opacity-100 group-hover:scale-100
                       group-focus-within:visible group-focus-within:opacity-100 group-focus-within:scale-100
                       transition-all duration-200 z-50"
          >
            {/* Mega menu card — theme-adaptive */}
            <div className="w-[720px] rounded-[28px] border p-6
                            bg-white border-gray-200 shadow-[0_24px_48px_-12px_rgba(0,0,0,0.12)]
                            dark:bg-[#25201d] dark:border-[#362f2a] dark:shadow-[0_24px_48px_-12px_rgba(0,0,0,0.4)]">
              <MegaMenuColumns
                columns={resourcesColumns}
                layout={resourcesLayout}
                featureBox={resourcesFeatureBox}
                onNavigate={closeAllMenus}
              />

              {/* Footer CTA row */}
              <div className="flex items-center gap-3 mt-5 pt-4 border-t border-gray-100 dark:border-white/5">
                <a
                  href={routes.resources}
                  onClick={closeAllMenus}
                  className="inline-flex items-center justify-center h-9 px-5 rounded-full bg-accent text-accent-contrast text-sm font-bold hover:bg-accent-hover transition-all"
                >
                  Browse Resources
                </a>
                <a
                  href={routes.contact}
                  onClick={closeAllMenus}
                  className="text-sm font-medium text-gray-500 dark:text-[#a39a92] hover:text-accent dark:hover:text-accent transition-colors"
                >
                  Ask a Question
                </a>
              </div>
            </div>
          </div>
        </div>

        {/* Right links (Career, Contact) */}
        {rightLinks.map((link) => (
          <a
            key={link.href}
            href={link.href}
            aria-current={isActive(link.href) ? "page" : undefined}
            onClick={closeAllMenus}
            className={cn(navLinkBase, isActive(link.href) && navLinkActive)}
          >
            {link.label}
          </a>
        ))}

        {/* Highlight link — Track Consultation (differentiator)
            Rendered as a distinctive accent pill with animated indicator dot.
            BACKEND: The label and href come from staticNavigation.ts highlightLink.
            The visual treatment (accent bg + pulsing dot) is hardcoded here. */}
        <a
          href={highlightLink.href}
          onClick={closeAllMenus}
          aria-current={isActive(highlightLink.href) ? "page" : undefined}
          className={cn(
            "relative inline-flex items-center gap-2 h-10 px-4 rounded-full text-sm font-extrabold transition-all",
            isActive(highlightLink.href)
              ? "bg-accent-hover text-accent-contrast ring-2 ring-accent/30"
              : "bg-accent text-accent-contrast hover:bg-accent-hover"
          )}
        >
          <span className="relative flex h-2 w-2" aria-hidden="true">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-accent-contrast opacity-75" />
            <span className="relative inline-flex rounded-full h-2 w-2 bg-accent-contrast" />
          </span>
          {highlightLink.label}
        </a>
      </nav>
    </div>
  );
}
