/**
 * MegaMenuColumns — Premium opaque dropdown content renderer.
 *
 * Supports two layout variants:
 *   - "split"   → 50/50 two-column grid, both sides contain link items
 *   - "feature" → 60/40 grid (col-span-7 / col-span-5),
 *                 left side has items, right side has feature box
 *
 * THEME ADAPTATION:
 * ─────────────────
 * Light mode: White/cream card with dark text
 * Dark mode: Opaque #25201d card with white text (the premium reference design)
 *
 * Styling tokens are applied via Tailwind dark: variant which maps to
 * data-theme="dark" via the @custom-variant in globals.css.
 *
 * BACKEND / ADMIN INTEGRATION NOTES:
 * ──────────────────────────────────
 * Menu content comes from staticNavigation.ts (or future API).
 * Each MenuItem can have an optional `description` for the subtitle.
 * The FeatureBox is configurable via the FeatureBox type.
 * To add items: update staticNavigation.ts and redeploy.
 */

import type { FeatureBox, MegaMenuLayout, MenuColumn } from "./types";

/* ── Feature Box Icons ── */
function NewspaperIcon() {
  return (
    <svg className="w-8 h-8 opacity-70" fill="none" stroke="currentColor" strokeWidth={1.5} viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" d="M12 7.5h1.5m-1.5 3h1.5m-7.5 3h7.5m-7.5 3h7.5m3-9h3.375c.621 0 1.125.504 1.125 1.125V18a2.25 2.25 0 0 1-2.25 2.25M16.5 7.5V18a2.25 2.25 0 0 0 2.25 2.25M16.5 7.5V4.875c0-.621-.504-1.125-1.125-1.125H4.125C3.504 3.75 3 4.254 3 4.875V18a2.25 2.25 0 0 0 2.25 2.25h13.5M6 7.5h3v3H6v-3Z" />
    </svg>
  );
}

function BriefcaseIcon() {
  return (
    <svg className="w-8 h-8 opacity-70" fill="none" stroke="currentColor" strokeWidth={1.5} viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" d="M20.25 14.15v4.25c0 1.094-.787 2.036-1.872 2.18-2.087.277-4.216.42-6.378.42s-4.291-.143-6.378-.42c-1.085-.144-1.872-1.086-1.872-2.18v-4.25m16.5 0a2.18 2.18 0 0 0 .75-1.661V8.706c0-1.081-.768-2.015-1.837-2.175a48.114 48.114 0 0 0-3.413-.387m4.5 8.006c-.194.165-.42.295-.673.38A23.978 23.978 0 0 1 12 15.75c-2.648 0-5.195-.429-7.577-1.22a2.016 2.016 0 0 1-.673-.38m0 0A2.18 2.18 0 0 1 3 12.489V8.706c0-1.081.768-2.015 1.837-2.175a48.111 48.111 0 0 1 3.413-.387m7.5 0V5.25A2.25 2.25 0 0 0 13.5 3h-3a2.25 2.25 0 0 0-2.25 2.25v.894m7.5 0a48.667 48.667 0 0 0-7.5 0" />
    </svg>
  );
}

function ChatIcon() {
  return (
    <svg className="w-8 h-8 opacity-70" fill="none" stroke="currentColor" strokeWidth={1.5} viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" d="M8.625 12a.375.375 0 1 1-.75 0 .375.375 0 0 1 .75 0Zm0 0H8.25m4.125 0a.375.375 0 1 1-.75 0 .375.375 0 0 1 .75 0Zm0 0H12m4.125 0a.375.375 0 1 1-.75 0 .375.375 0 0 1 .75 0Zm0 0h-.375M21 12c0 4.556-4.03 8.25-9 8.25a9.764 9.764 0 0 1-2.555-.337A5.972 5.972 0 0 1 5.41 20.97a5.969 5.969 0 0 1-.474-.065 4.48 4.48 0 0 0 .978-2.025c.09-.457-.133-.901-.467-1.226C3.93 16.178 3 14.189 3 12c0-4.556 4.03-8.25 9-8.25s9 3.694 9 8.25Z" />
    </svg>
  );
}

function CompassIcon() {
  return (
    <svg className="w-8 h-8 opacity-70" fill="none" stroke="currentColor" strokeWidth={1.5} viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" d="M12 21a9.004 9.004 0 0 0 8.716-6.747M12 21a9.004 9.004 0 0 1-8.716-6.747M12 21c2.485 0 4.5-4.03 4.5-9S14.485 3 12 3m0 18c-2.485 0-4.5-4.03-4.5-9S9.515 3 12 3m0 0a8.997 8.997 0 0 1 7.843 4.582M12 3a8.997 8.997 0 0 0-7.843 4.582m15.686 0A11.953 11.953 0 0 1 12 10.5c-2.998 0-5.74-1.1-7.843-2.918m15.686 0A8.959 8.959 0 0 1 21 12c0 .778-.099 1.533-.284 2.253m0 0A17.919 17.919 0 0 1 12 16.5a17.92 17.92 0 0 1-8.716-2.247m0 0A8.966 8.966 0 0 1 3 12c0-1.264.26-2.467.732-3.559" />
    </svg>
  );
}

function FeatureBoxIcon({ icon }: { icon: FeatureBox["icon"] }) {
  switch (icon) {
    case "newspaper": return <NewspaperIcon />;
    case "briefcase": return <BriefcaseIcon />;
    case "chat": return <ChatIcon />;
    case "compass": return <CompassIcon />;
    default: return <NewspaperIcon />;
  }
}

/* ── Single Menu Item Link ── */
function MegaMenuItem({
  item,
  onNavigate,
}: {
  item: { label: string; href: string; description?: string };
  onNavigate: () => void;
}) {
  return (
    <a
      href={item.href}
      onClick={onNavigate}
      className="group/item block px-3 py-2.5 rounded-2xl
                 hover:bg-white/[0.03] dark:hover:bg-white/[0.03]
                 hover:bg-gray-50
                 transition-colors duration-150"
    >
      <p className="text-[15px] font-medium text-gray-900 dark:text-white transition-colors">
        {item.label}
      </p>
      {item.description ? (
        <p className="text-xs text-gray-500 dark:text-[#a39a92] mt-0.5
                     group-hover/item:text-gray-700 dark:group-hover/item:text-[#c4bcb4]
                     transition-colors">
          {item.description}
        </p>
      ) : null}
    </a>
  );
}

/* ── Column Section (header + items) ── */
function MegaMenuColumn({
  column,
  onNavigate,
  showBorder,
}: {
  column: MenuColumn;
  onNavigate: () => void;
  showBorder?: boolean;
}) {
  return (
    <div className={`flex flex-col ${showBorder ? "pr-6 border-r border-gray-100 dark:border-white/5" : "pl-2"}`}>
      <div className="px-3 pb-2">
        <span className="text-[11px] font-bold tracking-wider uppercase text-gray-400 dark:text-[#a39a92]">
          {column.title}
        </span>
      </div>
      <div className="flex flex-col gap-1">
        {column.items.map((item, i) => (
          <MegaMenuItem key={`${column.title}-${item.href}-${i}`} item={item} onNavigate={onNavigate} />
        ))}
      </div>
    </div>
  );
}

/* ── Feature Box (right side of "feature" layout) ── */
function MegaMenuFeatureBox({ featureBox, onNavigate }: { featureBox: FeatureBox; onNavigate: () => void }) {
  return (
    <div className="col-span-5 flex flex-col items-center justify-center bg-[#ebe9e1] dark:bg-[#ebe9e1] rounded-2xl p-6 shadow-inner relative overflow-hidden">
      <div className="flex flex-col items-center text-center gap-3">
        <div className="text-[#4a433e]">
          <FeatureBoxIcon icon={featureBox.icon} />
        </div>
        <div>
          <h4 className="text-sm font-bold text-[#25201d] mb-1">
            {featureBox.title}
          </h4>
          <p className="text-xs text-[#6b6460] leading-relaxed max-w-[180px]">
            {featureBox.description}
          </p>
        </div>
        <a
          href={featureBox.ctaHref}
          onClick={onNavigate}
          className="mt-1 inline-flex items-center gap-1.5 px-4 py-2 rounded-full
                     bg-[#25201d] text-white text-xs font-bold
                     hover:bg-[#362f2a] transition-colors duration-150"
        >
          {featureBox.ctaLabel}
          <svg className="w-3 h-3" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round">
            <path d="M5 12h14M12 5l7 7-7 7" />
          </svg>
        </a>
      </div>
    </div>
  );
}

/* ═══════════════════════════════════════════════════════════
   MAIN EXPORT
   ═══════════════════════════════════════════════════════════ */
interface MegaMenuColumnsProps {
  columns: MenuColumn[];
  layout: MegaMenuLayout;
  featureBox?: FeatureBox;
  onNavigate: () => void;
}

export function MegaMenuColumns({ columns, layout, featureBox, onNavigate }: MegaMenuColumnsProps) {
  /* ── SPLIT LAYOUT (50/50) ── */
  if (layout === "split") {
    return (
      <div className="grid grid-cols-2 gap-6 text-left">
        {columns.map((column, index) => (
          <MegaMenuColumn
            key={`${column.title}-${index}`}
            column={column}
            onNavigate={onNavigate}
            showBorder={index === 0 && columns.length > 1}
          />
        ))}
      </div>
    );
  }

  /* ── FEATURE LAYOUT (60/40) ── */
  return (
    <div className="grid grid-cols-12 gap-6 text-left">
      {/* Left side: link columns */}
      <div className="col-span-7 flex flex-col gap-1 pr-4 border-r border-gray-100 dark:border-white/5">
        {columns.map((column, index) => (
          <div key={`${column.title}-${index}`} className={index > 0 ? "mt-3" : ""}>
            <div className="px-3 pb-2">
              <span className="text-[11px] font-bold tracking-wider uppercase text-gray-400 dark:text-[#a39a92]">
                {column.title}
              </span>
            </div>
            <div className="flex flex-col gap-1">
              {column.items.map((item, i) => (
                <MegaMenuItem key={`${column.title}-${item.href}-${i}`} item={item} onNavigate={onNavigate} />
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* Right side: feature box */}
      {featureBox ? (
        <MegaMenuFeatureBox featureBox={featureBox} onNavigate={onNavigate} />
      ) : null}
    </div>
  );
}
